import java.util.*;

class Solution {
	public boolean check_for_subsequence(String string_1, String string_2){
		int i=0, j=0;

		while(i < string_1.length() && j<string_2.length()){
			if(string_1.charAt(i) == string_2.charAt(j)){
				i++;
			}
			j++;
		}

		return i == string_1.length();
	}
	public boolean isPossible(String string_1, String string_2) {
		int count_1 = 0;
		int count_2 = 0;

		for(int i=1 ; i<string_1.length() ; i++){
			if(string_1.charAt(i)==string_2.charAt(i-1)){
				count_1++;
			}
			else{
				break;
			}
		}
		for(int i=1 ; i<string_2.length() ; i++){
			if(string_2.charAt(i) == string_2.charAt(i-1)){
				count_2++;
			}
			else{
				break;
			}
		}
		if(count_1 < count_2){
			return false;
		}
		if(check_for_subsequence(string_1, string_2)){
			return true;
		}
		return false;
	}
}

