import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class Test {

    Solution solution = new Solution();

    @Test
    void testBasicCases() {
        assertTrue(solution.isPossible("abc", "ahbgdc"), "Basic subsequence check failed");
        assertFalse(solution.isPossible("axc", "ahbgdc"), "Non-subsequence check failed");
    }

    @Test
    void testEdgeCases() {
        assertTrue(solution.isPossible("", "ahbgdc"), "Empty s should always return true");
        assertTrue(solution.isPossible("", ""), "Both strings empty should return true");
        assertTrue(solution.isPossible("a", "a"), "Single character matching");
        assertFalse(solution.isPossible("a", "b"), "Single character non-matching");
    }

    @Test
    void testNegativeCases() {
        assertFalse(solution.isPossible("abcd", "abc"), "s longer than t should return false");
    }

    @Test
    void testSpecialCases() {
        assertTrue(solution.isPossible("ace", "abcde"), "Non-consecutive subsequence");
        assertFalse(solution.isPossible("aec", "abcde"), "Characters not in order");
    }

    @Test
    void testIdenticalStrings() {
        assertTrue(solution.isPossible("abc", "abc"), "Identical strings should return true");
    }

    @Test
    void testLongStrings() {
        assertTrue(solution.isPossible("longstringtest", "longrandomstringtestforcheck"), "Long strings positive");
        assertFalse(solution.isPossible("longstringtest", "short"), "Long s with short t should return false");
    }
}
